12	@ccclass( "EnterRespinState" )
13	export class EnterRespinState extends BaseState
14	{
15	    private m_gameView: GameView = null;
16	
17	    /**@ch 等待時間（秒） */
18	    private static readonly WAIT_TIME = 0.8;
