26	    public async OnEnter()
27	    {
28	        console.log( "OnEnter State: ENTER_RESPIN" );
29	
30	        await Define.Wait(this.m_gameView, EnterRespinState.WAIT_TIME);
31	
32	        if (this.m_gameView.IsGoingToRespinGame)
33	        {
34	            // 設定 Respin 狀態
35	            this.m_gameView.IsRespinGame = true;
36	            this.m_gameView.IsGoingToRespinGame = false;
37	
38	            this.m_gameView.ClearAll();
39	
40	            // 處理轉輪
41	            this.HandleReel();
